SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

DROP TRIGGER IF EXISTS tbiu_sc_mem_m_member_memo ON sc_mem_m_member_memo CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_mem_m_member_memo() RETURNS trigger AS $BODY$
BEGIN
--return ;
  if coalesce(NEW.membership_no::text, '') = '' then
    CALL spa_dberrcol('sc_mem_m_member_special','membership_no',NEW.membership_no);
  end if;

  if coalesce(NEW.memo_code::text, '') = '' then
    NEW.memo_code := '99';
  end if;

  if coalesce(NEW.seq_no::text, '') = '' or NEW.seq_no = 0 then
    select max(seq_no) into STRICT NEW.seq_no
    from sc_mem_m_member_memo
    where (membership_no = NEW.membership_no);
    NEW.seq_no := coalesce(NEW.seq_no ,0) + 1;
  end if;

  if coalesce(NEW.entry_date::text, '') = '' then
    NEW.entry_date := statement_timestamp();
  end if;

  if coalesce(NEW.entry_id::text, '') = '' then
    NEW.entry_id := current_setting('app.login_id', true);
  end if;

  if coalesce(NEW.entry_br::text, '') = '' then
    NEW.entry_br := current_setting('app.login_br', true);
  end if;

  if coalesce(NEW.entry_pc::text, '') = '' then
    NEW.entry_pc := pka_com_login.login_pc;
  end if;

  if coalesce(NEW.cancel_status::text, '') = '' then
    NEW.cancel_status := '0';
  end if;

  if coalesce(NEW.memo_amount::text, '') = '' then
    NEW.memo_amount := 0;
  end if;

  --Niorn 2023-03-29 TGE งดหรือปลด ผ่าน Memo ให้มีผลทันที
  --CO หลักประกันบกพร่อง  งดทั้งหมด  ไม่ต้องยุ่งกับสถานะ lon_restruc
  --RR รับสภาพหนี้  งดทั้งหมด  ไม่ต้องยุ่งกับสถานะ lon_restruc
  --RE ผ่อนผัน          งดทั้งหมด  ไม่ต้องยุ่งกับสถานะ lon_restruc
  --RM คืนใบเสร็จ        งดทั้งหมด ไม่ต้องยุ่งกับสถานะ lon_restruc
  --LI เข้าโครงการ       งดทั้งหมด สถานะเข้าโครงการปรับโครงสร้างหนี้
  --LO ออกโครงการ      งดทั้งหมด สถานะเข้าโครงการปรับโครงสร้างหนี้  งดกู้ต่ออีก  รอดูผลการหักเงิน
--  if :new.memo_code = 'CO'  then
--    null ;
--  else
--      update  sc_mem_m_membership_registered
--      set     drop_loanemer_status = :new.drop_emer
--      where   membership_no = :new.membership_no ;  
--  end if ;
  
--  update  sc_mem_m_membership_registered
--  set     drop_loannormal_status = :new.drop_norm
--  where   membership_no = :new.membership_no ;
--  update  sc_mem_m_membership_registered
--  set     drop_loanspec_status = :new.drop_spec
--  where   membership_no = :new.membership_no ;
--  update  sc_mem_m_membership_registered
--  set     collactelral_status = :new.drop_coll
--  where   membership_no = :new.membership_no ;
  
    --Niorn 2023-08-04 TGE   ไม่ต้องยุ่งกับสถานะ lon_restruc   
    if NEW.memo_code = 'LI' or NEW.memo_code = 'LO'  then
          update  sc_mem_m_membership_registered
          set     lon_restruc = NEW.lon_restruc
          where   membership_no = NEW.membership_no;
    else
         select lon_restruc into STRICT  NEW.lon_restruc
         from sc_mem_m_membership_registered
         where membership_no = NEW.membership_no;
   end if;

  --แก้ไข memo ไม่รวมเพิ่มแถวน่ะ
  if ( (OLD.drop_emer IS NOT NULL AND OLD.drop_emer::text <> '') and NEW.drop_emer <> OLD.drop_emer )
    or ( (OLD.drop_norm IS NOT NULL AND OLD.drop_norm::text <> '') and NEW.drop_norm <> OLD.drop_norm )
    or ( (OLD.drop_spec IS NOT NULL AND OLD.drop_spec::text <> '') and NEW.drop_spec <> OLD.drop_spec )
    or ( (OLD.drop_coll IS NOT NULL AND OLD.drop_coll::text <> '') and NEW.drop_coll <> OLD.drop_coll )
    --or ( :old.lon_restruc  is not null and :new.lon_restruc <> :old.lon_restruc )
    or ( (OLD.memo_detail IS NOT NULL AND OLD.memo_detail::text <> '') and NEW.memo_detail <> OLD.memo_detail )
  then 

    --insert  SC_MEM_EDIT_MEMO
    INSERT INTO SC_MEM_EDIT_MEMO( membership_no,           entry_date,             entry_id,   
             operate_date,                
             PRE_MEMO_DETAIL,          PRE_DROP_EMER,         PRE_DROP_NORM,      PRE_DROP_SPEC,	    PRE_DROP_COLL,  PRE_LON_RESTRUC ,
             MEMO_DETAIL,          DROP_EMER,         DROP_NORM,      DROP_SPEC,	    DROP_COLL,   LON_RESTRUC
              )  
    VALUES ( NEW.membership_no,        statement_timestamp(),               current_setting('app.login_id', true),   
             TO_DATE( statement_timestamp() ),              
             OLD.MEMO_DETAIL,           OLD.DROP_EMER,       OLD.DROP_NORM,        OLD.DROP_SPEC,        OLD.DROP_COLL,   OLD.LON_RESTRUC,
             NEW.MEMO_DETAIL,         NEW.DROP_EMER,     NEW.DROP_NORM,       NEW.DROP_SPEC,       NEW.DROP_COLL ,   NEW.LON_RESTRUC
             ) 
;

  end if;
RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
-- REVOKE ALL ON FUNCTION trigger_fct_tbiu_sc_mem_m_member_memo() FROM PUBLIC;

CREATE TRIGGER tbiu_sc_mem_m_member_memo
	BEFORE INSERT OR UPDATE ON sc_mem_m_member_memo FOR EACH ROW
	EXECUTE PROCEDURE trigger_fct_tbiu_sc_mem_m_member_memo();

